UPDATE public.questions SET
  stimulus_text = 'The scientist’s research was groundbreaking, and her findings were widely discussed in the scientific community.  She was, however, a controversial figure, and many disagreed with her methods and interpretations. Subsequent paragraphs reinforce the same line of reasoning with additional examples, helping readers see how the author connects specific observations to a general claim without overstating certainty.',
  question_text = 'Which of the following best combines the two sentences at the underlined portion into a single sentence?  ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"She was, however, a controversial figure, and many disagreed with her methods and interpretations. ","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"However, she was a controversial figure, and many disagreed with her methods and interpretations.","is_correct":true,"explanation":"The best way to combine these sentences is to use the conjunction \"however\" to show the contrast between the two parts of the sentence.  The phrase \"however, she was\" is placed correctly because the conjunction \"however\" is a conjunctive adverb, which should be set off with a comma before and after. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"A controversial figure, however, she was, and many disagreed with her methods and interpretations.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"She was, however, a controversial figure because many disagreed with her methods and interpretations.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The best way to combine these sentences is to use the conjunction "however" to show the contrast between the two parts of the sentence.  The phrase "however, she was" is placed correctly because the conjunction "however" is a conjunctive adverb, which should be set off with a comma before and after it.  The phrase "and many disagreed with her methods and interpretations" is a dependent clause, which should also be set off with a comma before it. The passage states that "The scientist’s research was groundbreaking, and her findings were widely discussed in the scientific community. She was…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: However, she was a controversial figure, and many disagreed with her methods and interpretations.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":304,"opensat_domain":"Standard English Conventions","opensat_raw_id":"1111111","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.902Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
